# Run from contrib/Build/VS2022E oradjust the relative path
Get-ChildItem -Path (Resolve-Path "../../../../").Path -Filter *.exe -File | ForEach-Object { Write-Host "Testing: $($_.FullName)"; try { Start-Process -FilePath $_.FullName -NoNewWindow -Wait -PassThru -RedirectStandardOutput "stdout.log" -RedirectStandardError "stderr.log"; $stderr = Get-Content "stderr.log"; if ($stderr) { Write-Host "Error: $($_.Name) failed with AddressSanitizer errors." -ForegroundColor Red; Write-Host "ASan Details: $stderr" } else { Write-Host "Success: $($_.Name) ran without errors." -ForegroundColor Green } } catch { Write-Host "Error: $($_.Name) failed to run." -ForegroundColor Red; Write-Host "Details: $($_.Exception.Message)" } }
